#!/usr/bin/env python3
# apply_portraits.py — replace Hamlet + Frankenstein character portraits with the new
# character-sheet art. Overwrites existing asset indices (a42-a52 Hamlet, a53-a64 Frankenstein)
# in assets/assets.json with RAW base64 JPEG (no data: prefix — the src carries it inline).
# The game source (game.src.html) does NOT change; only the assets do.
# Re-running is safe. Usage from repo root:  python3 apply_portraits.py  &&  python3 build.py
import json, os, sys

root = os.path.dirname(os.path.abspath(__file__))
AJ = os.path.join(root, 'assets', 'assets.json')

# asset-id -> raw base64 JPEG (Hamlet a42-a52, Frankenstein a53-a64)
NEW = {
  "a42": "",
  "a43": "",
  "a44": "",
  "a45": "",
  "a46": "",
  "a47": "",
  "a48": "",
  "a49": "",
  "a50": "",
  "a51": "",
  "a52": "",
  "a53": "",
  "a54": "",
  "a55": "",
  "a56": "",
  "a57": "",
  "a58": "",
  "a59": "",
  "a60": "",
  "a61": "",
  "a62": "",
  "a63": "",
  "a64": "",
}

if not os.path.exists(AJ):
    sys.exit("[apply] assets/assets.json not found — run from the repo root.")
a = json.load(open(AJ))
def raw_only(v):
    i = v.find('base64,')
    return v[i+7:] if i != -1 else v
changed=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if a.get(k)!=nv: a[k]=nv; changed.append(k)
json.dump(a, open(AJ,'w'))
print(f"[apply] portraits -> updated {len(changed)} assets: {sorted(changed, key=lambda x:int(x[1:])) or '(none)'}")
print("[apply] done. Next: python3 build.py")
